diff --git a/src/__tests__/wait-for-element.js b/src/__tests__/wait-for-element.js
index d8883d0..aa9a8f9 100644
--- a/src/__tests__/wait-for-element.js
+++ b/src/__tests__/wait-for-element.js
@@ -2,6 +2,7 @@ import {waitForElement, wait} from '../'
 // adds special assertions like toBeTruthy
 import 'jest-dom/extend-expect'
 import {render} from './helpers/test-utils'
+import document from './helpers/document'

 const skipSomeTime = delayMs =>
   new Promise(resolve => setTimeout(resolve, delayMs))
@@ -320,7 +321,14 @@ test('works if a container is not defined', async () => {
   const successHandler = jest.fn().mockName('successHandler')
   const errorHandler = jest.fn().mockName('errorHandler')

-  waitForElement(callback).then(successHandler, errorHandler)
+  if (typeof window === 'undefined') {
+    waitForElement(callback, {container: document}).then(
+      successHandler,
+      errorHandler,
+    )
+  } else {
+    waitForElement(callback).then(successHandler, errorHandler)
+  }

   await skipSomeTimeForMutationObserver()

@@ -342,7 +350,14 @@ test('throws an error if callback is not a function', async () => {
   const successHandler = jest.fn().mockName('successHandler')
   const errorHandler = jest.fn().mockName('errorHandler')

-  waitForElement().then(successHandler, errorHandler)
+  if (typeof window === 'undefined') {
+    waitForElement(undefined, {container: document}).then(
+      successHandler,
+      errorHandler,
+    )
+  } else {
+    waitForElement().then(successHandler, errorHandler)
+  }

   await skipSomeTimeForMutationObserver()

diff --git a/src/__tests__/pretty-dom.js b/src/__tests__/pretty-dom.js
index 4d81267..312cf78 100644
--- a/src/__tests__/pretty-dom.js
+++ b/src/__tests__/pretty-dom.js
@@ -10,3 +10,7 @@ test('it supports truncating the output length', () => {
   const {container} = render('<div>Hello World!</div>')
   expect(prettyDOM(container, 5)).toMatch(/\.\.\./)
 })
+
+test('it supports receiving the document element', () => {
+  expect(prettyDOM(document)).toMatchSnapshot()
+})

diff --git a/src/__tests__/wait-for-dom-change.js b/src/__tests__/wait-for-dom-change.js
index c843bb6..3db4d77 100644
--- a/src/__tests__/wait-for-dom-change.js
+++ b/src/__tests__/wait-for-dom-change.js
@@ -1,16 +1,8 @@
+import {waitForDomChange} from '..'
 import {renderIntoDocument} from './helpers/test-utils'

-function importModule() {
-  return require('../').waitForDomChange
-}
-
-let waitForDomChange
-
-beforeEach(() => {
+afterEach(() => {
   jest.useRealTimers()
-  jest.resetModules()
-  waitForDomChange = importModule()
-  console.warn.mockClear()
 })

 test('waits for the dom to change in the document', async () => {
@@ -35,13 +27,6 @@ test('waits for the dom to change in the document', async () => {
       },
     ]
   `)
-  expect(console.warn.mock.calls).toMatchInlineSnapshot(`
-Array [
-  Array [
-    "\`waitForDomChange\` has been deprecated. Use \`waitFor\` instead: https://testing-library.com/docs/dom-testing-library/api-async#waitfor.",
-  ],
-]
-`)
 })

 test('waits for the dom to change in a specified container', async () => {
@@ -67,36 +52,3 @@ test('waits for the dom to change in a specified container', async () => {
     ]
   `)
 })
-
-describe('timers', () => {
-  const expectElementToChange = async () => {
-    const importedWaitForDomChange = importModule()
-    const {container} = renderIntoDocument('<div />')
-
-    setTimeout(() => container.firstChild.setAttribute('id', 'foo'), 100)
-
-    const promise = importedWaitForDomChange({container, timeout: 200})
-
-    if (setTimeout._isMockFunction) {
-      jest.advanceTimersByTime(110)
-    }
-
-    await expect(promise).resolves.toMatchSnapshot()
-  }
-
-  it('works with real timers', async () => {
-    jest.useRealTimers()
-    await expectElementToChange()
-  })
-  it('works with fake timers', async () => {
-    jest.useFakeTimers()
-    await expectElementToChange()
-  })
-})
-
-test("doesn't change jest's timers value when importing the module", () => {
-  jest.useFakeTimers()
-  importModule()
-
-  expect(window.setTimeout._isMockFunction).toEqual(true)
-})
